using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF 9 changed discriminator from "Discriminator" to "$type".
            // Preserve old property name so existing 500K documents stay readable.
            entity.HasDiscriminator<string>("Discriminator");

            // EF 9 changed id format from "Product|123" to just "123".
            // Preserve the old format so existing documents keep their ids.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });

        // HasIndex is removed — EF 9 Cosmos provider now throws instead of
        // silently ignoring it. Cosmos doesn't support secondary indexes this way.
    }
}
